mapper.select:
select 
from drive_space
where user_id = #{userId, jdbcType=BINARY}

select 
from drive_space
where space_id = #{spaceId, jdbcType=BINARY}

mapper.update:
update drive_space
set reserved_bytes = reserved_bytes + #{bytes},
    updated_at = #{updatedAt}
where space_id = #{spaceId, jdbcType=BINARY}
  and used_bytes + reserved_bytes + #{bytes} <= quota_bytes

update drive_space
set used_bytes = used_bytes + #{bytes},
    reserved_bytes = reserved_bytes - #{bytes},
    updated_at = #{updatedAt}
where space_id = #{spaceId, jdbcType=BINARY}
  and reserved_bytes >= #{bytes}
  and used_bytes + #{bytes} <= quota_bytes

update drive_space
set reserved_bytes = greatest(0, reserved_bytes - #{bytes}),
    updated_at = #{updatedAt}
where space_id = #{spaceId, jdbcType=BINARY}

update drive_space
set quota_bytes = #{quotaBytes},
    used_bytes = #{usedBytes},
    reserved_bytes = #{reservedBytes},
    updated_at = #{updatedAt}
where space_id = #{spaceId, jdbcType=BINARY}
